  9	  Button,
 10	  ButtonVariant,
 11	  Flex,
 12	  Icon,
 13	  List,
 14	  ListItem,
 15	  Popover,
 16	  Stack,
 17	  StackItem,
 18	} from '@patternfly/react-core';
 19	import { TimesIcon } from '@patternfly/react-icons';
 20	import { getName, getNamespace } from '@utils/crds/common/selectors';
 21	
 22	import { STATUS_POPOVER_VMS_COUNT_THRESHOLD } from './utils/constants';
 23	import { migrationStatusIconMap } from './utils/statusIconMapper';
 24	import {
 25	  type MigrationVirtualMachinesStatusCountObjectVM,
 26	  MigrationVirtualMachineStatus,
 27	} from './utils/types';
 28	import { getPopoverMessageByStatus } from './utils/utils';
 29	
 30	type StatusPopoverProps = {
 31	  status: MigrationVirtualMachineStatus;
 32	  count: number;
 33	  vms: MigrationVirtualMachinesStatusCountObjectVM[];
 34	  plan: V1beta1Plan;
 35	};
 36	
 37	const StatusPopover: FC<StatusPopoverProps> = ({ count, plan, status, vms }) => {
 38	  const { showModal } = useModal();
 39	  const navigate = useNavigate();
 40	
 41	  const { actionLabel, body, header } = getPopoverMessageByStatus(status, count);
 42	
 43	  const openScheduleCutoverModal = () => {
 44	    showModal(<PlanCutoverMigrationModal plan={plan} />);
 45	  };
 46	
 47	  const navigateToVMsTab = () => {
 48	    const url = `${getResourceUrl({ name: getName(plan), namespace: getNamespace(plan), reference: PlanModelRef })}/vms`;
 49	    navigate(url);
 50	  };
 51	  return (
 52	    <Popover
 53	      triggerAction="hover"
 54	      headerContent={header}
 55	      bodyContent={
 56	        <Stack hasGutter>
 57	          {body && <StackItem>{body}</StackItem>}
 58	          <StackItem>
 59	            <List>
 60	              {vms.map(({ failedTaskName, name }, idx) => {
 61	                if (idx >= STATUS_POPOVER_VMS_COUNT_THRESHOLD) return null; // show only first items
 62	                return (
 63	                  <ListItem key={name}>
 64	                    {name}
 65	                    {failedTaskName && (
 66	                      <ListItem
 67	                        icon={
 68	                          <Icon status="danger">
 69	                            <TimesIcon />
 70	                          </Icon>
 71	                        }
 72	                      >
 73	                        {failedTaskName}
 74	                      </ListItem>
 75	                    )}
 76	                  </ListItem>
 77	                );
 78	              })}
 79	            </List>
 80	          </StackItem>
 81	
 82	          <StackItem>
 83	            <Button
 84	              variant={ButtonVariant.link}
 85	              onClick={() => {
 86	                if (status === MigrationVirtualMachineStatus.Paused) {
 87	                  openScheduleCutoverModal();
 88	                  return;
 89	                }
 90	
 91	                navigateToVMsTab();
 92	              }}
 93	              isInline
 94	            >
 95	              {actionLabel}
 96	            </Button>
 97	          </StackItem>
 98	        </Stack>
 99	      }
100	    >
101	      <Flex gap={{ default: 'gapXs' }}>
102	        {migrationStatusIconMap[status]}
103	        <Button isInline variant={ButtonVariant.link} onClick={navigateToVMsTab}>
104	          {count}
105	        </Button>
106	      </Flex>
107	    </Popover>
108	  );
109	};
110	
111	export default StatusPopover;

